#include<bits/stdc++.h>
using namespace std;
long long n,Q,dfn[300010],siz[300010],dfncnt;
long long sum[300010],d[300010],ans[300010];
vector<long long> mp[300010];
struct query
{
    long long l,r,y,id;
    bool operator<(const query&b)const
    {
        return y<b.y;
    }
}q[600010];
struct node
{
    long long x,y,val;
    bool operator<(const node&b)const
    {
        return y<b.y;
    }
}p[300010];
void dfs(long long x,long long fa=-1)
{
    dfn[x]=++dfncnt;
    siz[x]=1;
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            d[i]=d[x]+1;
            dfs(i,x);
            siz[x]+=siz[i];
        }
    }
}
long long lowbit(long long x)
{
    return x&-x;
}
void add(long long x,long long v)
{
    for(long long i=x;i<=n;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
long long Query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
int main()
{
    scanf("%lld%lld",&n,&Q);
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    long long k=0;
    for(long long i=1;i<=n;i++)
    {
        p[i]=(node){dfn[i],d[i],siz[i]-1};
    }
    for(long long i=1;i<=Q;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        ans[i]+=(siz[x]-1)*min(d[x],y);
        q[++k]=(query){dfn[x],dfn[x]+siz[x]-1,d[x],-i};
        q[++k]=(query){dfn[x],dfn[x]+siz[x]-1,d[x]+y,i};
    }
    sort(p+1,p+1+n);
    sort(q+1,q+1+k);
    long long j=1;
    for(long long i=1;i<=k;i++)
    {
        while(j<=n&&p[j].y<=q[i].y)
        {
            add(p[j].x,p[j].val);
            j++;
        }
        if(q[i].id>0)
        {
            ans[q[i].id]+=Query(q[i].r)-Query(q[i].l-1);
        }
        else
        {
            ans[-q[i].id]-=Query(q[i].r)-Query(q[i].l-1);
        }
    }
    for(long long i=1;i<=Q;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
